var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"죄수 이송용 승강궤도- 특수무기징역수 올리비에 콜먼.","JPN":"囚人移送用の昇降軌道 - 特殊無期懲役囚、オリヴィエ・コールマン。","ENG":"Prisoner Transfer Elevation Tracks - Special Life Sentence Prisoner: Olivie Coleman.","TWN":"用於押送囚犯的軌道升降機——特殊武器罪犯奧利維亞·科曼。","THA":"ลิฟต์วงโคจรที่ใช้ในการขนส่งนักโทษ - อาชญากรอาวุธพิเศษ โอลิวี่ โคลแมน","VTN":"Thang máy dùng để vận chuyển tù nhân - Tội phạm vũ khí đặc biệt Olivia Coleman.","SCN":"囚犯移送用升降轨道，特殊无期徒刑罪犯 奥利维亚·科尔曼 运输中","DEU":"Hebegleis für den Transport von Gefangenen – Olivie Coleman, Sonderhäftling mit lebenslanger Haftstrafe.","FRA":"Ascenseur pour le transfert des prisonniers - Olivie Coleman, prisonnière condamnée à perpétuité."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"챔버 도시관리국 관할 우주정거장 교도소, 아케론 입소 전.","JPN":"チェンバー都市管理局管轄の宇宙ステーション刑務所、アケロンの入所前。","ENG":"Before entering Acheron, the Chamber City Management Jurisdiction Space Station Penitentiary.","TWN":"強巴城市管理局管轄的太空站，黃泉入監前。","THA":"ห้องประชุม: ศูนย์ฝึกอบรมสถานีอวกาศภายใต้เขตอำนาจขององค์การบริหารเมือง หน้าทางเข้าแอเคอรอน","VTN":"Phòng hội thảo: Trung tâm đào tạo trạm vũ trụ thuộc quản lý của Cục Quản Lý, trước cổng Acheron.","SCN":"会议室城市管理局管辖的空间站监狱——阿刻戎 入所前。","DEU":"Vor dem Betreten von Akeron – ein Raumstationsgefängnis unter dem Zuständigkeitsbereich der Stadtverwaltung Chamber.","FRA":"Aux portes d'Achéron, la prison de la station spatiale sous la juridiction de la Direction des cités de Chamber."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_A","text":{"KOREA":"여기는 G플랫폼. 수용 절차를 마친 죄수가 승강궤도에 탑승합니다.","JPN":"こちら、プラットフォームG。収容手続きを終えた囚人が、昇降軌道に搭乗します。","ENG":"Calling from Platform G. The prisoner completed her admittance procedure and is stepping aboard the elevation tracks.","TWN":"這裡是G平台，完成收監程序的囚犯將登上軌道升降機。"},"stage":{"bg":"LIFT","slots":{"L":null,"C":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"확인했습니다. 죄수 이송을 위해 G플랫폼의 아케론 승강궤도 진입을 허가합니다.","JPN":"確認しました。囚人移送のため、プラットフォームGのアケロン昇降軌道進入を許可します。","ENG":"Confirmed. Granting access to Platform G's Acheron elevation tracks for prisoner transfer.","TWN":"已確認，授權G平台為押送囚犯進入黃泉軌道升降機。"},"stage":{"bg":"LIFT","slots":{"L":null,"C":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_A","text":{"KOREA":"어지간한 범죄로는 큐브까지 올 일은 없을 텐데, 꼬맹이가 아주 엄청난 짓을 저질렀나보군.","JPN":"中途半端な犯罪ならキューブまで来ないはずだ。チビのくせにとんでもねえことをしでかしたんだな。","ENG":"No ordinary crime would get you all the way to the cube. The kid must've done something huge.","TWN":"竟然被送到了魔方，這小鬼肯定幹了什麼驚天動地的大事。"},"stage":{"bg":"LIFT","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_B","text":{"KOREA":"법정 경비원한테 듣기론 자기가 속해 있던 태스크포스를 돈 때문에 배신했다고 하던데.","JPN":"法廷の警備員に聞いたんだが、所属していたタスクフォースを金のために裏切ったらしいぞ。","ENG":"A court guard told me she betrayed her own TASKFORCE for money.","TWN":"法院保全說她為了錢背叛了自己所屬的特遣勢力。"},"stage":{"bg":"LIFT","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_B","text":{"KOREA":"작전지역에서 대원들을 버리고 떠난 것도 모자라 회사 건물을 주먹으로 부쉈다 봐.","JPN":"作戦地域で隊員を捨てた上に、会社のビルを拳で破壊したとか。","ENG":"Not only did she abandon her troops and run away from the operation area, but she also punched the company building until it collapsed.","TWN":"她不僅在戰區拋棄了自己的隊員們，還用拳頭破壞了公司的大樓。"},"stage":{"bg":"LIFT","slots":{"L":{"char_id":"GUARD_NPC_PRISONER_B","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFT","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"관리자님의 계획대로라면, 스승님께선 위조된 죄수 신분으로 무사히 아케론 수감소에 들어가실 수 있을 겁니다.","JPN":"管理者さんの計画どおりなら、師匠は偽造した囚人の身分で無事アケロン収容所まで入れるはずです。","ENG":"According to the Administrator's plan, you should be able to enter Acheron Penitentiary as a fake prisoner without any problems.","TWN":"如果管理者的計畫順利進行，師父應該能以偽造囚犯的身分順利進入黃泉收押所。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"알겠다.","JPN":"了解した。","ENG":"Understood.","TWN":"知道了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그 녀석 계획이란 건 마음에 안 들지만 어쩔 수 없지.","JPN":"あいつの計画というのは気に入らないが、仕方ない。","ENG":"I'm not happy with the fact that it was his plan, but I guess I have no choice.","TWN":"雖然不喜歡他的計畫，但沒辦法了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"죄수 이송 목적 외에는 결코 문을 열지 않는 감옥입니다. 기회는 단 한 번이에요.","JPN":"囚人移送の目的以外には、決して扉を開かない監獄です。チャンスはこの一度だけですよ。","ENG":"The prison never opens its gates for purposes other than prisoner transfers. You only have one opportunity.","TWN":"這個監獄的大門只會為押送囚犯的用途打開，機會只有一次。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러니 아케론에 도착하기 전까진 절대, 소란을 피워서 일을 망치시면 안 됩니다.","JPN":"ですから、アケロンに着くまでは絶対、騒ぎを起こして気づかれないようにしてください。","ENG":"So whatever happens, do not attract any attention to yourself and mess this up until you arrive at Acheron.","TWN":"所以在抵達黃泉之前，千萬不要引起騷亂。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"쓸데없는 걱정이군. 그럴 일은 없을 거다.","JPN":"杞憂だな。","ENG":"No need to worry. That won't happen.","TWN":"別擔心，不會發生這種事。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GUARD_NPC_PRISONER_A","text":{"KOREA":"이런 꼬맹이가 주먹으로 건물을 부쉈다고?","JPN":"こんなチビが、拳でビルを破壊しただと？","ENG":"This kid made a building collapse with her fists?","TWN":"這孩子用拳頭破壞了一棟樓？"},"stage":{"bg":"LIFT","slots":{"L":null,"C":{"char_id":"GUARD_NPC_PRISONER_A","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};